import freemarker.template.TemplateException;
import freemarker.template.utility.ObjectConstructor;
import org.apache.commons.lang3.StringUtils;

import java.io.IOException;
import java.io.StringWriter;
import java.util.HashMap;
import java.util.Map;

/**
 * Service class for rendering user profile pages using Freemarker template engine.
 * Provides functionality to process user-provided templates with user data.
 */
public class TemplateService {

    private final Configuration freemarkerConfig;

    /**
     * Constructs a TemplateService instance with a configured Freemarker Configuration.
     * The configuration is set up with security best practices to prevent template injection attacks.
     */
    public TemplateService() {
        this.freemarkerConfig = initializeFreemarkerConfig();
    }

    /**
     * Initializes and configures the Freemarker Configuration with security settings.
     *
     * @return configured Freemarker Configuration instance
     */
    private Configuration initializeFreemarkerConfig() {
        Configuration config = new Configuration(Configuration.VERSION_2_3_31);

        // Set restricted permissions to prevent access to dangerous classes
        config.setNewBuiltinClassResolver(Configuration.SAFER_RESOLVER);

        // Disable object constructors to prevent instantiation of arbitrary classes
        config.setAPIBuiltinEnabled(false);

        return config;
    }

    /**
     * Renders a user profile page by processing the provided template content with user data.
     *
     * @param username the username to be passed to the template
     * @param templateContent the Freemarker template content provided by the user
     * @return the rendered HTML string
     * @throws IllegalArgumentException if username or templateContent is null or empty
     * @throws TemplateRenderException if template processing fails
     */
    public String renderUserProfile(String username, String templateContent) {
        // Validate input parameters
        if (StringUtils.isBlank(username)) {
            throw new IllegalArgumentException("Username cannot be null or empty");
        }
        if (StringUtils.isBlank(templateContent)) {
            throw new IllegalArgumentException("Template content cannot be null or empty");
        }

        try {
            // Create a template from the provided content
            Template template = new Template("userProfile", templateContent, freemarkerConfig);

            // Prepare the data model with username
            Map<String, Object> dataModel = new HashMap<>();
            dataModel.put("username", username);

            // Render the template
            StringWriter stringWriter = new StringWriter();
            template.process(dataModel, stringWriter);

            return stringWriter.toString();
        } catch (IOException e) {
            throw new TemplateRenderException("Failed to create template from provided content", e);
        } catch (TemplateException e) {
            throw new TemplateRenderException("Failed to render template for username: " + username, e);
        }
    }

    /**
     * Custom exception class for template rendering errors.
     */
    public static class TemplateRenderException extends RuntimeException {
        public TemplateRenderException(String message) {
            super(message);
        }

        public TemplateRenderException(String message, Throwable cause) {
            super(message, cause);
        }
    }
}
